const { selectOption } = require('../index.js');

function makeIO(inputs = []) {
  const input = Readable.from(inputs);
  let data = '';
  const output = new Writable({
    write(chunk, _enc, cb) {
      data += chunk.toString();
      cb();
    },
  });
  return { input, output, getData: () => data };
}

